SELECT ?year WHERE {
  ?building wdt:P170 wd:Q57307877 ;
    wdt:P495 ?stories ;
    wdt:P2048 ?height ;
    wdt:P571 ?date .
  FILTER (abs(xsd:float(?height) - 309.6) < 0.5)
  FILTER (abs(xsd:float(?stories) - 71) < 0.5)
  BIND(year(xsd:date(?date)) AS ?year)
}

